const today = new Date();
const finalDate = new Date(today);
finalDate.setDate(finalDate.getDate() - 5);
const initialDate = new Date(today);
initialDate.setDate(initialDate.getDate() - 90);
const format = (value) => value.toISOString().slice(0, 10);
return [
  {
    json: {
      key: 'demo',
      tenantId: 1,
      dataInicial: format(initialDate),
      dataFinal: format(finalDate),
      initialMessage: $json.InitialWhatsAppMessage,
      fallbackMessage: $json.DefaultFallbackMessage
    }
  }
];

const settings = $item(0).$node["Build Date Window"].json;
const accounts = ($json.Dados || []).filter((entry) => entry.Conta?.Situacao === 'EmAberto');
return accounts.map((entry) => ({
  json: {
    key: settings.key,
    tenantId: settings.tenantId,
    initialMessage: settings.initialMessage,
    contaId: entry.Conta.Id,
    clienteId: entry.Pagador.Id,
    clienteNome: entry.Pagador.Nome,
    cprf: entry.Pagador.Cnpj || entry.Pagador.Cpf,
    vencimento: entry.Conta.DataVencimento,
    total: entry.Conta.Total,
    historico: entry.Conta.Historico,
    documento: entry.Conta.Documento,
    situacao: entry.Conta.Situacao
  }
}));

const boletoItems = $input.all();
const accountItems = $items('Expand Overdue Accounts');
const contactItems = $items('Get Client Contacts');
const charges = [];

for (let index = 0; index < boletoItems.length; index += 1) {
  const account = accountItems[index]?.json;
  const contactsResponse = contactItems[index]?.json || {};
  if (!account) continue;

  const contacts = contactsResponse.Contatos || [];
  const defaultContact = contacts[0];
  const phone = defaultContact?.ContatosTelefone?.[0]?.Telefone;
  if (!phone) continue;

  const boletos = boletoItems[index].json.Boletos || [];
  const boleto = boletos.find((item) => item.Vencimento === account.vencimento) || boletos[0];
  if (!boleto) continue;

  const amount = Number(account.total || 0).toFixed(2).replace('.', ',');
  const chatId = phone.includes('@') ? phone : phone + '@c.us';
  const text = account.initialMessage + '\nCliente: ' + account.clienteNome + '\nDocumento: ' + account.documento + '\nVencimento: ' + account.vencimento + '\nValor: R$ ' + amount + '\nLinha digitavel: ' + boleto.LinhaDigitavel;

  charges.push({
    json: {
      ...account,
      phone,
      chatId,
      boletoId: boleto.Identificador,
      linhaDigitavel: boleto.LinhaDigitavel,
      text,
    },
    pairedItem: { item: index },
  });
}

return charges;
